import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Instalar Mods","description":"Una guía paso a paso sobre como instalar mods para Fabric.","frontmatter":{"title":"Instalar Mods","description":"Una guía paso a paso sobre como instalar mods para Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"es_es/1.21.1/players/installing-mods.md","filePath":"versions/1.21.1/translated/es_es/players/installing-mods.md","lastUpdated":1761424914000}`);var s={name:`es_es/1.21.1/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalar Mods <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalar Mods”">​</a></h1><p>Esta guía te enseñará sobre como instalar mods para Fabric usando el Launcher de Minecraft.</p><p>Para launchers o lanzadores de terceros, consulta su documentación.</p><h2 id="_1-descarga-el-mod" tabindex="-1">1. Descarga el Mod <a class="header-anchor" href="#_1-descarga-el-mod" aria-label="Permalink to “1. Descarga el Mod”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Solo deberías descargar mods desde fuentes en las que confíes. Para mayor información sobre como encontrar mods, visita la guía sobre <a href="./finding-mods">Encontrar Mods Confiables</a>.</p></div><p>La mayoría de los mods requieren Fabric API, el cual puede ser descargado desde <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> o <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a></p><p>Cuando descargues mods, asegúrate que:</p><ul><li>Son compatibles con la versión de Minecraft en la que juegues. Por ejemplo, un mod que funcione en la versión 1.20, puede que no funcione en la versión 1.20.2.</li><li>Son hechos para Fabric y no otro lanzador de mods (mod loader).</li><li>Finalmente, que sean compatibles con la edición de Minecraft correcta (Edición de Java).</li></ul><h2 id="_2-mueve-el-archivo-del-mod-al-folder-de-mods" tabindex="-1">2. Mueve el archivo del mod al folder de <code>mods</code> <a class="header-anchor" href="#_2-mueve-el-archivo-del-mod-al-folder-de-mods" aria-label="Permalink to “2. Mueve el archivo del mod al folder de mods”">​</a></h2><p>El folder de mods puede ser encontrado en las siguientes localizaciones dependiendo de tu sistema operativo.</p><p>Usualmente puedes copiar y pegar estas direcciones de archivo en la barra de direcciones de tu explorador de archivos para encontrar el folder rápidamente.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Una vez que hayas encontrado el folder de <code>mods</code>, puedes colocar el archivo <code>.jar</code> del mod ahí.</p><p><img src="/assets/players/installing-mods.png" alt="Mods instalados en el folder de mods" loading="lazy"></p><h2 id="_3-¡hemos-terminado" tabindex="-1">3. ¡Hemos terminado! <a class="header-anchor" href="#_3-¡hemos-terminado" aria-label="Permalink to “3. ¡Hemos terminado!”">​</a></h2><p>¡Una vez que hayas movido los mods al folder de <code>mods</code>, puedes abrir el Launcher de Minecraft, seleccionar el perfil de Fabric desde el menú deslizador en la esquina inferior izquierda y presionar Jugar!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher de Minecraft con el perfil de Fabric seleccionado" loading="lazy"></p><h2 id="solucionar-problemas" tabindex="-1">Solucionar Problemas <a class="header-anchor" href="#solucionar-problemas" aria-label="Permalink to “Solucionar Problemas”">​</a></h2><p>Si encuentras problemas tratando de seguir esta guía, puedes solicitar ayuda en el servidor de <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord de Fabric</a>, en el canal de <code>#player-support</code>.</p><p>También puedes intentar solucionar el problema tu mismo leyendo las guías sobre como solucionar problemas:</p><ul><li><a href="./troubleshooting/crash-reports">Reportes de Crasheo</a></li><li><a href="./troubleshooting/uploading-logs">Subir Logs</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};